const staticData = $getWorkflowStaticData('global');
staticData.remindedKeys = staticData.remindedKeys || {};
// Purge keys older than 14 days
const cutoff = Date.now() - 14 * 86400000;
for (const k in staticData.remindedKeys) {
  if (staticData.remindedKeys[k] < cutoff) delete staticData.remindedKeys[k];
}

const now = new Date();
const todayStr = now.toISOString().split('T')[0];
const tomorrow = new Date(now); tomorrow.setDate(tomorrow.getDate() + 1);
const tomorrowStr = tomorrow.toISOString().split('T')[0];
const hour = parseInt(new Intl.DateTimeFormat('en-GB', { timeZone: 'Asia/Jerusalem', hour: '2-digit', hour12: false }).format(now));

const items = $input.first().json?.data?.boards?.[0]?.groups?.[0]?.items_page?.items || [];
const reminders = [];
for (const item of items) {
  const due = (item.column_values || []).find(c => c.id === 'date');
  const status = (item.column_values || []).find(c => c.id === 'project_status');
  const priority = (item.column_values || []).find(c => c.id === 'priority');
  if (!due?.text) continue;
  if (status?.text === 'Done') continue;
  const dueDate = due.text.split(' ')[0];

  // 24h-before reminder (fire once when due is tomorrow, any hour)
  if (dueDate === tomorrowStr) {
    const key = `24h-${item.id}-${dueDate}`;
    if (!staticData.remindedKeys[key]) {
      staticData.remindedKeys[key] = Date.now();
      reminders.push({ json: { type: '24h', itemId: item.id, itemName: item.name, dueDate, priority: priority?.text || '', url: `https://alex-it.monday.com/boards/5093821351/pulses/${item.id}` } });
    }
  }

  // Day-of reminder at 9am Israel
  if (dueDate === todayStr && hour === 9) {
    const key = `day-${item.id}-${dueDate}`;
    if (!staticData.remindedKeys[key]) {
      staticData.remindedKeys[key] = Date.now();
      reminders.push({ json: { type: 'today', itemId: item.id, itemName: item.name, dueDate, priority: priority?.text || '', url: `https://alex-it.monday.com/boards/5093821351/pulses/${item.id}` } });
    }
  }
}
return reminders;

